import { describe, expect, it } from "vitest"
import { render, screen } from "@testing-library/react"
import Card from "@/components/ui/Card"

describe("Card Component", () => {
  it("renders its children", () => {
    render(
      <Card>
        <p>Card content</p>
      </Card>,
    )

    expect(screen.getByText("Card content")).toBeInTheDocument()
  })

  it("applies core layout and surface styling classes", () => {
    const { container } = render(
      <Card>
        <p>Card content</p>
      </Card>,
    )

    const card = container.firstElementChild
    expect(card).toHaveClass(
      "rounded-ui-xl",
      "border",
      "border-app-border",
      "bg-app-surface",
      "shadow-soft",
      "flex",
      "flex-col",
      "gap-4",
      "p-18",
    )
  })
})

import { describe, expect, it } from "vitest"
import { render, screen } from "@testing-library/react"
import Error from "@/components/Error"

describe("Error Component", () => {
  it("renders internal error mode with request id and retry action", () => {
    render(<Error requestId="req-123" />)

    expect(screen.getByRole("heading", { name: "Internal error" })).toBeInTheDocument()
    expect(screen.getByText("req-123")).toBeInTheDocument()
    expect(screen.getByRole("link", { name: "Try again" })).toHaveAttribute("href", "/timesheets")
    expect(screen.getByRole("link", { name: "Return to overview" })).toHaveAttribute("href", "/")
  })

  it("renders global error mode with message and timestamp", () => {
    render(<Error global globalErrorMessage="Database unavailable" />)

    expect(screen.getByRole("heading", { name: "Global error" })).toBeInTheDocument()
    expect(screen.getByText("Database unavailable")).toBeInTheDocument()
    expect(screen.getByText(/time stamp:/i)).toBeInTheDocument()
  })

  it("hides retry action in global mode", () => {
    render(<Error global globalErrorMessage="Database unavailable" />)

    expect(screen.queryByRole("link", { name: "Try again" })).not.toBeInTheDocument()
    expect(screen.getByRole("link", { name: "Return to overview" })).toBeInTheDocument()
  })
})

import { describe, expect, it } from "vitest"
import { render, screen } from "@testing-library/react"
import Loading from "@/components/Loading"

describe("Loading Component", () => {
  it("renders loading text", () => {
    render(<Loading />)

    expect(screen.getByText("Loading...")).toBeInTheDocument()
  })

  it("uses the loading class on the root element", () => {
    const { container } = render(<Loading />)

    expect(container.firstElementChild).toHaveClass("loading")
  })
})

import { describe, expect, it } from "vitest"
import { render, screen } from "@testing-library/react"
import LoadingBadge from "@/components/ui/LoadingBadge"

describe("LoadingBadge Component", () => {
  it("renders the loading label", () => {
    render(<LoadingBadge>Saving changes...</LoadingBadge>)

    expect(screen.getByText("Saving changes...")).toBeInTheDocument()
  })

  it("renders a spinner with animation classes", () => {
    const { container } = render(<LoadingBadge>Loading</LoadingBadge>)

    const spinner = container.querySelector("span")
    expect(spinner).toHaveClass(
      "w-5",
      "h-5",
      "rounded-full",
      "border-[3px]",
      "border-teal-100",
      "border-t-teal-700",
      "animate-spin",
    )
  })

  it("applies badge container styling", () => {
    const { container } = render(<LoadingBadge>Loading</LoadingBadge>)

    const badge = container.firstElementChild
    expect(badge).toHaveClass(
      "inline-flex",
      "items-center",
      "rounded-xl",
      "border",
      "border-teal-100",
      "bg-teal-50",
      "text-slate-600",
    )
  })
})

import { describe, expect, it } from "vitest"
import { render, screen } from "@testing-library/react"
import LoadingSkeleton, {
  ManagementSkeleton,
  OverviewSkeleton,
  ReportsSkeleton,
  TimesheetSkeleton,
} from "@/components/ui/LoadingSkeleton"

describe("LoadingSkeleton Component", () => {
  it("renders the overview skeleton layout", () => {
    const { container } = render(<OverviewSkeleton />)

    expect(container.querySelector(".bg-teal-50\\/50")).toBeInTheDocument()
  })

  it("renders the timesheet skeleton layout", () => {
    const { container } = render(<TimesheetSkeleton />)

    expect(container.querySelector(".grid-cols-7")).toBeInTheDocument()
  })

  it("renders the management skeleton layout", () => {
    const { container } = render(<ManagementSkeleton />)

    expect(container.querySelectorAll(".h-9.w-28")).toHaveLength(4)
  })

  it("renders the reports skeleton layout", () => {
    const { container } = render(<ReportsSkeleton />)

    expect(container.querySelector(".sm\\:grid-cols-\\[120px_1fr_64px\\]")).toBeInTheDocument()
  })

  it("shows the profile placeholder for profile page", () => {
    render(<LoadingSkeleton page="profile" />)

    expect(screen.getByText("To be built")).toBeInTheDocument()
  })
})

import { describe, expect, it, vi } from "vitest"
import { render, screen } from "@testing-library/react"
import NavButton from "@/components/NavButton"

const { mockUsePathname } = vi.hoisted(() => ({
  mockUsePathname: vi.fn(),
}))

vi.mock("next/navigation", () => ({
  usePathname: mockUsePathname,
}))

describe("NavButton Component", () => {
  it("renders a navigation link with title and href", () => {
    mockUsePathname.mockReturnValue("/")

    render(
      <NavButton
        title="Overview"
        href="/"
        badge={null}
        icon={<span aria-hidden="true">I</span>}
      />,
    )

    expect(screen.getByRole("link", { name: "Overview" })).toHaveAttribute("href", "/")
  })

  it("marks active links with aria-current", () => {
    mockUsePathname.mockReturnValue("/reports")

    render(
      <NavButton
        title="Reports"
        href="/reports"
        badge={null}
        icon={<span aria-hidden="true">I</span>}
      />,
    )

    expect(screen.getByRole("link", { name: "Reports" })).toHaveAttribute("aria-current", "page")
  })

  it("renders the badge text when provided", () => {
    mockUsePathname.mockReturnValue("/")

    render(
      <NavButton
        title="Management"
        href="/management"
        badge="Manager"
        icon={<span aria-hidden="true">I</span>}
      />,
    )

    expect(screen.getByText("Manager")).toBeInTheDocument()
  })

  it("shows the management indicator dot for manager badge", () => {
    mockUsePathname.mockReturnValue("/management")

    const { container } = render(
      <NavButton
        title="Management"
        href="/management"
        badge="Manager"
        icon={<span aria-hidden="true">I</span>}
      />,
    )

    expect(container.querySelector(".bg-teal-500")).toBeInTheDocument()
  })
})

import { describe, expect, it, vi } from "vitest"
import { render, screen } from "@testing-library/react"
import React from "react"
import Navbar from "@/components/Navbar"

vi.mock("next/image", () => ({
  default: ({ src, alt, className }: { src: string; alt: string; className?: string }) =>
    React.createElement("img", { src, alt, className }),
}))

describe("Navbar Component", () => {
  it("renders branding and main navigation entries", () => {
    render(<Navbar userType="User" />)

    expect(screen.getByText("PolyTime")).toBeInTheDocument()
    expect(screen.getByRole("link", { name: "Overview" })).toBeInTheDocument()
    expect(screen.getByRole("link", { name: "Timesheet" })).toBeInTheDocument()
    expect(screen.getByRole("link", { name: "Reports" })).toBeInTheDocument()
    expect(screen.getByRole("link", { name: "Profile" })).toBeInTheDocument()
    expect(screen.getByRole("link", { name: /Management/ })).toBeInTheDocument()
  })

  it("applies sidebar shell classes", () => {
    const { container } = render(<Navbar userType="User" />)

    const aside = container.querySelector("aside")
    expect(aside).toHaveClass("fixed", "left-0", "w-20", "lg:w-64", "bg-cyan-950")
  })

  it("shows manager badge only for manager user type", () => {
    const { rerender } = render(<Navbar userType="User" />)
    expect(screen.queryByText("Manager")).not.toBeInTheDocument()

    rerender(<Navbar userType="Manager" />)
    expect(screen.getByText("Manager")).toBeInTheDocument()
  })
})

import { describe, expect, it } from "vitest"
import { render, screen } from "@testing-library/react"
import NotFound from "@/components/NotFound"

describe("NotFound Component", () => {
  it("renders the not found heading and message", () => {
    render(<NotFound />)

    expect(screen.getByRole("heading", { name: "404 · Page not found" })).toBeInTheDocument()
    expect(screen.getByText("We could not find the page you were looking for.")).toBeInTheDocument()
  })

  it("renders both reroute actions with expected hrefs", () => {
    render(<NotFound />)

    expect(screen.getByRole("link", { name: "Go to Timesheets" })).toHaveAttribute("href", "/timesheets")
    expect(screen.getByRole("link", { name: "Open overview" })).toHaveAttribute("href", "/")
  })

  it("uses centered page layout and icon styling classes", () => {
    const { container } = render(<NotFound />)

    expect(container.querySelector("[id='404-page-container']")).toHaveClass("flex", "items-center", "justify-center", "h-full")
    expect(container.querySelector("[id='404-icon']")).toHaveClass("bg-teal-100/60", "text-teal-800", "rounded-2xl")
  })
})
